const base = env.get('RADARR_URL');
const key = env.get('RADARR_API_KEY');
if (!base) { node.error('RADARR_URL not set'); return null; }
if (!key) { node.error('RADARR_API_KEY not set'); return null; }
const { query } = msg.payload || {};
msg.url = `${base}/api/v3/movie/lookup?term=${encodeURIComponent(query)}`;
msg.headers = { 'X-Api-Key': key };
return msg;

if (msg.statusCode >= 400) { msg.payload = JSON.stringify({ error: `HTTP ${msg.statusCode}` }); return msg; }
const arr = Array.isArray(msg.payload) ? msg.payload : [];
msg.payload = JSON.stringify(arr.slice(0, 10).map(m => ({
  id: m.id || null,
  title: m.title,
  year: m.year || null,
  tmdbId: m.tmdbId || null,
  hasFile: m.hasFile || false,
  monitored: m.monitored || false,
  status: m.status || null,
  overview: (m.overview || '').slice(0, 200) || null,
  poster: ((m.images || []).find(i => i.coverType === 'poster') || {}).remoteUrl || null
})));
return msg;

const base = env.get('RADARR_URL');
const key = env.get('RADARR_API_KEY');
if (!base) { node.error('RADARR_URL not set'); return null; }
if (!key) { node.error('RADARR_API_KEY not set'); return null; }
const { radarr_id } = msg.payload || {};
msg.url = `${base}/api/v3/movie/${radarr_id}`;
msg.headers = { 'X-Api-Key': key };
return msg;

if (msg.statusCode >= 400) { msg.payload = JSON.stringify({ error: `HTTP ${msg.statusCode}` }); return msg; }
const m = msg.payload || {};
const f = m.movieFile || null;
msg.payload = JSON.stringify({
  id: m.id,
  title: m.title,
  year: m.year || null,
  tmdbId: m.tmdbId || null,
  hasFile: m.hasFile || false,
  monitored: m.monitored || false,
  status: m.status || null,
  overview: (m.overview || '').slice(0, 300) || null,
  path: m.path || null,
  sizeOnDisk: m.sizeOnDisk || 0,
  quality: f ? (f.quality && f.quality.quality ? f.quality.quality.name : null) : null
});
return msg;
